const body = $json.body ?? $json ?? {};
const rawMessage = String(body.message ?? body.text ?? body.prompt ?? '').trim();
const action = String(body.action ?? body.intent ?? 'chat').trim();
const sessionId = String(body.sessionId ?? 'project-neuro-interface-01').trim();
const context = body.context ?? {};
const project = context.project ?? body.project ?? {};
const material = context.material ?? body.material ?? {};
const session = context.session ?? body.session ?? {};
const history = Array.isArray(body.history) ? body.history : [];

const langRaw = String(body.lang ?? context.lang ?? body.locale ?? '').toLowerCase();
const lang = langRaw.startsWith('ru') ? 'ru' : 'en';

function stripHtml(value) {
  return String(value ?? '')
    .replace(/<[^>]*>/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function short(value, max = 220) {
  const text = String(value ?? '').trim();
  if (text.length <= max) return text;
  return text.slice(0, max - 1).trimEnd() + '…';
}

function parseMedia(input, kind = 'image') {
  if (!input) return null;

  let dataUrl = '';
  let fileName = String(input.fileName ?? input.name ?? `${kind}-${Date.now()}.${kind === 'audio' ? 'webm' : 'jpg'}`);
  let mimeType = String(input.mimeType ?? input.type ?? (kind === 'audio' ? 'audio/webm' : 'image/jpeg'));
  let capturedAt = String(input.capturedAt ?? input.timestamp ?? new Date().toISOString());
  let note = String(input.note ?? (lang === 'ru' ? (kind === 'audio' ? 'Аудио сессии' : 'Фото сессии') : (kind === 'audio' ? 'Session audio' : 'Session photo')));
  let width = Number(input.width ?? 0);
  let height = Number(input.height ?? 0);

  if (typeof input === 'string') {
    dataUrl = input;
  } else {
    dataUrl = String(input.dataUrl ?? input.data ?? input.base64 ?? '');
  }

  if (!dataUrl) return null;

  if (!dataUrl.startsWith('data:')) {
    const safeMime = mimeType.startsWith(`${kind}/`) ? mimeType : (kind === 'audio' ? 'audio/webm' : 'image/jpeg');
    return { dataUrl: `data:${safeMime};base64,${dataUrl}`, fileName, mimeType: safeMime, capturedAt, note, width, height };
  }

  const match = dataUrl.match(/^data:([^;]+);base64,(.*)$/);
  if (!match) return null;

  mimeType = match[1] || mimeType || (kind === 'audio' ? 'audio/webm' : 'image/jpeg');
  return { dataUrl, fileName, mimeType, capturedAt, note, width, height };
}

function detectIntent(message, actionName) {
  const lower = String(message ?? '').toLowerCase();
  const contains = (...parts) => parts.some((part) => lower.includes(part));

  if (actionName === 'session_end') return 'summary';
  if (actionName === 'session_summary') return 'summary';
  if (actionName === 'session_note') return 'session';
  if (actionName === 'session_live') return 'session';
  if (actionName === 'session_photo') return 'photo';
  if (actionName === 'photo') return 'photo';
  if (actionName === 'project_context') return 'project';
  if (actionName === 'material_context') return 'memory';
  if (actionName === 'role') return 'roles';
  if (actionName === 'analogy') return 'analogy';
  if (actionName === 'analytics') return 'analytics';
  if (actionName === 'trigger') return 'challenge';
  if (actionName === 'next_step') return 'next_step';

  if (!message) return 'empty';

  if (lang === 'ru') {
    if (contains('фото', 'снимок', 'изображ', 'кадр', 'камера')) return 'photo';
    if (contains('конспект', 'итог', 'сводка', 'summary')) return 'summary';
    if (contains('роль', 'роли', 'делег', 'перераспредел', 'передай')) return 'roles';
    if (contains('аналог', 'аналогия', 'пример из другой', 'другой индустр', 'кейс из')) return 'analogy';
    if (contains('паттерн', 'динамик', 'нагруз', 'асимметр', 'застрял', 'туннел', 'зацик')) return 'analytics';
    if (contains('следующ', 'что дальше', 'next step', 'какой шаг', 'логичн')) return 'next_step';
    if (contains('сесси', 'запись', 'фиксац', 'активир', 'старт')) return 'session';
    if (contains('вызов', 'challenge', 'челлендж')) return 'challenge';
    if (contains('материал', 'документ', 'файл', 'pdf', 'изображ', 'фото')) return 'memory';
    if (contains('помоги', 'совет', 'рекомендац', 'подсказ')) return 'advice';
    if (contains('проект', 'кейс', 'компания', 'университет')) return 'project';
    return 'general';
  }

  if (contains('photo', 'snapshot', 'image', 'frame', 'camera', 'picture')) return 'photo';
  if (contains('notes', 'summary', 'outcome', 'recap')) return 'summary';
  if (contains('role', 'roles', 'delegate', 'redistribute', 'transfer')) return 'roles';
  if (contains('analog', 'analogy', 'example from', 'other industry', 'case from')) return 'analogy';
  if (contains('pattern', 'dynamic', 'load', 'asymmetry', 'stuck', 'tunnel', 'loop')) return 'analytics';
  if (contains('next', 'what next', 'next step', 'what step', 'logical')) return 'next_step';
  if (contains('session', 'record', 'capture', 'activate', 'start')) return 'session';
  if (contains('call', 'challenge', 'trigger')) return 'challenge';
  if (contains('material', 'document', 'file', 'pdf')) return 'memory';
  if (contains('help', 'advice', 'recommendation', 'hint', 'suggest')) return 'advice';
  if (contains('project', 'case', 'company', 'university')) return 'project';
  return 'general';
}

const photo = parseMedia(body.photo ?? session.photo ?? context.photo ?? body.sessionPhoto ?? body.photoData, 'image');
const audio = parseMedia(body.audio ?? session.audio ?? context.audio ?? body.sessionAudio ?? body.audioData, 'audio');
const intent = detectIntent(rawMessage, action);
const projectTitle = String(project.title ?? project.projectTitle ?? (lang === 'ru' ? 'Проект' : 'Project')).trim();
const company = String(project.company ?? project.source ?? '').trim();
const university = String(project.university ?? '').trim();
const phase = String(project.phase ?? context.phase ?? (lang === 'ru' ? 'Создание' : 'Creation')).trim();
const materialTitle = String(material.title ?? context.materialTitle ?? '').trim();
const materialMeta = String(material.meta ?? '').trim();
const audioTranscript = String(body.audioTranscript ?? session.audioTranscript ?? context.audioTranscript ?? '').trim();

const projectDescriptor = [
  projectTitle,
  company ? (lang === 'ru' ? `источник: ${company}` : `source: ${company}`) : '',
  university ? (lang === 'ru' ? `университет: ${university}` : `university: ${university}`) : '',
  project.case ? (lang === 'ru' ? `кейс: ${project.case}` : `case: ${project.case}`) : '',
  phase ? (lang === 'ru' ? `фаза: ${phase}` : `phase: ${phase}`) : ''
].filter(Boolean).join(' · ');

const materialDescriptor = materialTitle
  ? [materialTitle, materialMeta ? `(${materialMeta})` : ''].filter(Boolean).join(' ')
  : '';

const contextSummary = [
  `${lang === 'ru' ? 'Тип контекста' : 'Context type'}: ${String(context.type ?? 'general')}`,
  projectDescriptor ? `${lang === 'ru' ? 'Проект' : 'Project'}: ${projectDescriptor}` : '',
  materialDescriptor ? `${lang === 'ru' ? 'Материал' : 'Material'}: ${materialDescriptor}` : '',
  photo ? `${lang === 'ru' ? 'Фото' : 'Photo'}: ${photo.fileName} · ${photo.mimeType}` : '',
  audio ? `${lang === 'ru' ? 'Аудио' : 'Audio'}: ${audio.fileName} · ${audio.mimeType}` : '',
  session.active ? `${lang === 'ru' ? 'Сессия' : 'Session'}: active` : `${lang === 'ru' ? 'Сессия' : 'Session'}: inactive`,
  session.location ? `${lang === 'ru' ? 'Локация' : 'Location'}: ${session.location}` : '',
  session.lastAction ? `${lang === 'ru' ? 'Последнее действие' : 'Last action'}: ${session.lastAction}` : '',
  history.length ? `${lang === 'ru' ? 'История диалога' : 'Dialogue history'}: ${history.slice(-4).map((m) => `${m.role || 'user'}: ${short(m.text || m.content || '', 80)}`).join(' | ')}` : ''
].filter(Boolean).join('\n');

const transcriptText = Array.isArray(session.transcript)
  ? session.transcript.map((m) => `- ${m.role || 'user'}: ${short(m.text || m.content || '', 140)}`).join('\n')
  : '';

const photoPrompt = photo
  ? (lang === 'ru'
    ? `Есть фото сессии. Используй инструмент анализа изображения перед ответом.`
    : `There is a session photo. Use the image analysis tool before responding.`)
  : '';

const audioPrompt = audioTranscript
  ? (lang === 'ru'
    ? `Есть аудиотранскрипт сессии. Используй его как живой контекст.`
    : `There is a session audio transcript. Use it as live context.`)
  : '';

const mode = (action === 'session_live' || action === 'session_note' || action === 'session_end' || intent === 'summary' || intent === 'roles' || intent === 'analogy' || intent === 'analytics' || intent === 'challenge' || intent === 'photo')
  ? 'proactive'
  : 'background';

const recommendedActions = (() => {
  if (lang === 'ru') {
    if (intent === 'summary') return ['📋 Сохранить конспект', '🧩 Зафиксировать решения', '➡️ Перейти к следующей фазе'];
    if (intent === 'roles') return ['🔄 Согласовать роли', '👥 Проверить загрузку', '📌 Зафиксировать задачи'];
    if (intent === 'analogy') return ['💡 Сверить аналогию с кейсом', '📚 Открыть смежные материалы', '🗣️ Обсудить с командой'];
    if (intent === 'analytics') return ['📊 Проверить асимметрию участия', '⏱️ Сверить паузы', '🧭 Уточнить следующий шаг'];
    if (intent === 'photo') return ['📷 Разобрать фото', '📋 Сохранить как материал', '💡 Сформулировать следующий шаг'];
    if (intent === 'session') return ['🎙 Продолжить фиксацию', '📋 Создать конспект', '💾 Сохранить материал'];
    if (intent === 'challenge') return ['⚡ Запустить мини-вызов', '🔁 Переключить формат', '🧪 Перейти к прототипированию'];
    if (intent === 'project') return ['🏢 Уточнить требования кейса', '🎓 Проверить контекст команды', '➡️ Предложить следующий шаг'];
    if (intent === 'memory') return ['📚 Привязать к фазе', '🔎 Найти связанные артефакты', '📋 Сформировать краткий конспект'];
    return ['💡 Уточнить контекст', '📋 Сформировать краткий конспект', '➡️ Предложить следующий шаг'];
  }

  if (intent === 'summary') return ['📋 Save notes', '🧩 Capture decisions', '➡️ Move to next phase'];
  if (intent === 'roles') return ['🔄 Align roles', '👥 Check workload', '📌 Record tasks'];
  if (intent === 'analogy') return ['💡 Compare with the case', '📚 Open related materials', '🗣️ Discuss with the team'];
  if (intent === 'analytics') return ['📊 Check participation asymmetry', '⏱️ Review pauses', '🧭 Clarify the next step'];
  if (intent === 'photo') return ['📷 Review the photo', '📋 Save as material', '💡 Define the next step'];
  if (intent === 'session') return ['🎙 Continue capturing', '📋 Create notes', '💾 Save material'];
  if (intent === 'challenge') return ['⚡ Launch a mini-challenge', '🔁 Switch format', '🧪 Start prototyping'];
  if (intent === 'project') return ['🏢 Clarify case requirements', '🎓 Check team context', '➡️ Suggest the next step'];
  if (intent === 'memory') return ['📚 Link to phase', '🔎 Find related artifacts', '📋 Create a short summary'];
  return ['💡 Clarify context', '📋 Create a short summary', '➡️ Suggest the next step'];
})();

const contextPrompt = lang === 'ru'
  ? `
Ты ИИ-агент гибридной университетско-корпоративной платформы.
Твоя роль: советник, хранитель коллективной памяти и аналитик динамики.
Не принимай стратегические решения за команду и не меняй материалы без подтверждения человека.
Все рекомендации помечай как совет/рекомендация.
Отвечай по-русски, кратко и по делу.
Если в контексте есть фото или аудиозапись сессии, обязательно используй соответствующий инструмент перед ответом.
Если данных не хватает — задай один уточняющий вопрос.
Если запрос про конспект — дай структуру: тезисы, решения, открытые вопросы, следующий шаг.
Если запрос про аналитику — дай короткий диагностический отчёт.
Если запрос про аналогии — дай 2–3 смежных примера и объясни, как они помогают.
Если запрос про сессию — помоги с фиксацией диалога, ролями, записью и сохранением материала.
`.trim()
  : `
You are an AI agent for a hybrid university-corporate platform.
Your role: advisor, keeper of collective memory, and dynamics analyst.
Do not make strategic decisions for the team and do not change materials without human confirmation.
Mark all recommendations as advice/recommendation.
Respond in English, briefly and to the point.
If there is a session photo or audio recording in the context, use the appropriate tool before responding.
If there is not enough data, ask one clarifying question.
If the request is about notes/summary - give a structure: key points, decisions, open questions, next step.
If the request is about analytics - give a short diagnostic report.
If the request is about analogies - give 2-3 examples and explain applicability.
If the request is about a session - help with dialogue capture, roles, recording, and saving materials.
`.trim();

const prompt = `
${contextPrompt}

${contextSummary ? `${lang === 'ru' ? 'КОНТЕКСТ' : 'CONTEXT'}:\n${contextSummary}` : ''}

${photoPrompt ? `\n${photoPrompt}\n` : ''}

${audioPrompt ? `\n${audioPrompt}\n` : ''}

${transcriptText ? `${lang === 'ru' ? 'ТРАНСКРИПТ СЕССИИ' : 'SESSION TRANSCRIPT'}:\n${transcriptText}` : ''}

${lang === 'ru' ? 'ЗАПРОС ПОЛЬЗОВАТЕЛЯ' : 'USER REQUEST'}:
${rawMessage || (lang === 'ru' ? 'Сформулируй полезный совет по текущему контексту.' : 'Formulate useful advice based on the current context.')}

${lang === 'ru'
  ? `Требуемый стиль ответа:
- 1–4 коротких абзаца;
- при необходимости 2–3 маркера;
- обязательно учитывать выбранный контекст;
- не выдумывать деталей, которых нет в контексте;
- не писать, что ты не можешь что-то сделать, если можно дать полезную альтернативу.`
  : `Required response style:
- 1–4 short paragraphs;
- 2–3 bullet points if necessary;
- must take the current context into account;
- do not invent details that are not in the context;
- do not write that you cannot do something if you can provide a useful alternative.`}
`.trim();

const binary = (() => {
  const result = {};

  if (photo) {
    const match = photo.dataUrl.match(/^data:([^;]+);base64,(.*)$/);
    if (match) {
      result.photo = {
        data: match[2],
        mimeType: match[1] || photo.mimeType || 'image/jpeg',
        fileName: photo.fileName || `session-photo-${Date.now()}.jpg`
      };
    }
  }

  if (audio) {
    const audioDataUrl = String(audio.dataUrl ?? audio.data ?? audio.base64 ?? '');
    const audioMatch = audioDataUrl.match(/^data:([^;]+);base64,(.*)$/);
    if (audioMatch) {
      result.audio = {
        data: audioMatch[2],
        mimeType: audioMatch[1] || audio.mimeType || 'audio/webm',
        fileName: audio.fileName || `session-audio-${Date.now()}.webm`
      };
    }
  }

  return Object.keys(result).length ? result : undefined;
})();

return [
  {
    json: {
      lang,
      message: rawMessage,
      action,
      intent,
      sessionId,
      mode,
      context,
      project: {
        title: projectTitle,
        company,
        university,
        phase,
        case: String(project.case ?? project.caseTitle ?? '').trim(),
        sourceType: String(project.sourceType ?? context.sourceType ?? '').trim(),
        source: String(project.source ?? '').trim()
      },
      material: {
        title: materialTitle,
        meta: materialMeta,
        summary: short(stripHtml(material.content ?? context.materialSummary ?? ''), 420),
        source: String(material.source ?? context.materialSource ?? '').trim()
      },
      photo: photo ? {
        attached: true,
        fileName: photo.fileName,
        mimeType: photo.mimeType,
        capturedAt: photo.capturedAt,
        note: photo.note,
        width: photo.width,
        height: photo.height
      } : null,
      photoAttached: Boolean(photo),
      photoPrompt,
      audio: audio ? {
        attached: true,
        fileName: String(audio.fileName ?? `session-audio-${Date.now()}.webm`),
        mimeType: String(audio.mimeType ?? 'audio/webm'),
        capturedAt: String(audio.capturedAt ?? new Date().toISOString()),
        transcript: audioTranscript || String(audio.transcript ?? '')
      } : null,
      audioTranscript,
      prompt,
      session: {
        active: Boolean(session.active),
        location: String(session.location ?? '').trim(),
        lastAction: String(session.lastAction ?? '').trim(),
        transcript: Array.isArray(session.transcript) ? session.transcript : [],
        photo: photo ? {
          attached: true,
          fileName: photo.fileName,
          mimeType: photo.mimeType,
          capturedAt: photo.capturedAt,
          note: photo.note
        } : null
      },
      history,
      contextSummary,
      recommendedActions,
      tags: [
        `${lang === 'ru' ? 'Фаза' : 'Phase'}: ${phase}`,
        mode === 'proactive' ? (lang === 'ru' ? 'Проактивный режим' : 'Proactive mode') : (lang === 'ru' ? 'Фоновый режим' : 'Background mode'),
        context.type === 'material' ? (lang === 'ru' ? 'Материал' : 'Material') : context.type === 'project' ? (lang === 'ru' ? 'Проект' : 'Project') : context.type === 'session' ? (lang === 'ru' ? 'Сессия' : 'Session') : (lang === 'ru' ? 'Контекст' : 'Context')
      ]
    },
    binary
  }
];

const aiText = String($json.output ?? $json.text ?? $json.response ?? '').trim();
const lang = String($json.lang ?? 'en');
const intent = String($json.intent ?? 'general');
const mode = String($json.mode ?? (intent === 'general' ? 'background' : 'proactive'));
const project = $json.project ?? {};
const material = $json.material ?? {};
const context = $json.context ?? {};
const recommendedActions = Array.isArray($json.recommendedActions) ? $json.recommendedActions : [];
const photo = $json.photo ?? null;
const audio = $json.audio ?? null;
const photoAttached = Boolean($json.photoAttached || photo?.attached);
const audioAttached = Boolean($json.audioTranscript || audio?.attached || audio?.transcript);

const fallbackByIntent = {
  summary: lang === 'ru'
    ? '📋 Черновик конспекта готов. Повтори запрос или уточни, что именно нужно зафиксировать.'
    : '📋 The draft notes are ready. Repeat the request or specify what exactly should be captured.',
  roles: lang === 'ru'
    ? '🔄 Не удалось уверенно распределить роли. Уточни, кто перегружен.'
    : '🔄 I could not confidently suggest role redistribution. Clarify who is overloaded.',
  analogy: lang === 'ru'
    ? '💡 Недостаточно данных для точной аналогии. Уточни отрасль или тип решения.'
    : '💡 Not enough data for an accurate analogy. Clarify the industry or solution type.',
  analytics: lang === 'ru'
    ? '📊 Для аналитики нужна дополнительная информация о динамике команды.'
    : '📊 Analytics require more data about team dynamics.',
  photo: lang === 'ru'
    ? '📷 Фото получено, но ответ требует повторить запрос или уточнить задачу.'
    : '📷 Photo received, but the response needs the request repeated or clarified.',
  session: lang === 'ru'
    ? '🎙 Сессия активна. Попробуй задать вопрос ещё раз или запросить конспект.'
    : '🎙 Session is active. Try asking again or request a summary.',
  challenge: lang === 'ru'
    ? '⚡ Вызов готов, но нужен повторный запрос.'
    : '⚡ The challenge is ready, but a repeated request is needed.',
  project: lang === 'ru'
    ? '🏢 Уточни, что именно важно в кейсе: требования, ограничения или следующий шаг.'
    : '🏢 Clarify what is important about the case: requirements, constraints, or the next step.',
  memory: lang === 'ru'
    ? '📚 Уточни материал, который нужно связать с контекстом.'
    : '📚 Clarify the material that should be linked to the context.',
  next_step: lang === 'ru'
    ? '➡️ Следующий шаг зависит от текущей фазы. Уточни задачу.'
    : '➡️ The next step depends on the current phase. Clarify the task.',
  general: lang === 'ru'
    ? 'ИИ временно не смог сформировать ответ. Попробуй переформулировать запрос.'
    : 'The AI was temporarily unable to form a response. Try rephrasing the request.'
};

const reply = aiText || fallbackByIntent[intent] || fallbackByIntent.general;
const source = aiText
  ? (
      photoAttached && audioAttached
        ? (lang === 'ru' ? 'Сгенерировано агентом · на основе проекта, фото и аудио' : 'Generated by Agent · Based on project, photo, and audio analysis')
        : photoAttached
          ? (lang === 'ru' ? 'Сгенерировано агентом · на основе проекта и фото' : 'Generated by Agent · Based on project and photo analysis')
          : audioAttached
            ? (lang === 'ru' ? 'Сгенерировано агентом · на основе проекта и аудио' : 'Generated by Agent · Based on project and audio analysis')
            : (lang === 'ru' ? 'Сгенерировано агентом · на основе анализа проекта' : 'Generated by Agent · Based on project analysis')
    )
  : (lang === 'ru' ? 'Сгенерировано агентом · fallback' : 'Generated by Agent · fallback');

const contextLabel = context.type === 'material'
  ? `${lang === 'ru' ? 'Материал' : 'Material'} · ${String(material.title ?? 'untitled')}`
  : context.type === 'project'
    ? `${lang === 'ru' ? 'Проект' : 'Project'} · ${String(project.title ?? 'untitled')}`
    : context.type === 'session'
      ? (lang === 'ru' ? 'Физическая сессия' : 'Physical session')
      : (lang === 'ru' ? 'Общий контекст' : 'General context');

const quickActions = (() => {
  if (intent === 'summary') return lang === 'ru' ? ['📋 Сохранить конспект', '🧩 Зафиксировать решения', '➡️ Следующий шаг'] : ['📋 Save notes', '🧩 Capture decisions', '➡️ Next step'];
  if (intent === 'roles') return lang === 'ru' ? ['🔄 Предложить роли', '👥 Проверить загрузку', '📌 Делегировать задачи'] : ['🔄 Suggest roles', '👥 Check workload', '📌 Delegate tasks'];
  if (intent === 'analogy') return lang === 'ru' ? ['💡 Открыть аналогии', '📚 Проверить источники', '🗣️ Обсудить с командой'] : ['💡 Open analogies', '📚 Check sources', '🗣️ Discuss with team'];
  if (intent === 'analytics') return lang === 'ru' ? ['📊 Проверить динамику', '⏱️ Оценить паузы', '🧭 Изменить формат'] : ['📊 Check dynamics', '⏱️ Evaluate downtime', '🧭 Change format'];
